import { useEffect, useState } from "react";
import axios from "axios";
import {
  Box, Typography, Button,
  Table, TableHead, TableRow,
  TableCell, TableBody, Paper,
  FormControl, InputLabel, Select, MenuItem,
  Dialog, DialogTitle, DialogContent,
  Snackbar, Alert
} from "@mui/material";

import jsPDF from "jspdf";
import autoTable from "jspdf-autotable";

import Header from "../components/header";
import AdminSidebar from "../components/sidebar";

/* ================= AUTO ALLOCATION ================= */
function allocateStudents(students, room) {
  const seated = students.slice(0, room.capacity);
  const overflow = students.slice(room.capacity);
  return { seated, overflow };
}

export default function AdminSeating() {

  const [departments, setDepartments] = useState([]);
  const [students, setStudents] = useState([]);
  const [staffList, setStaffList] = useState([]);
  const [rooms, setRooms] = useState([]);

  const [selectedDepts, setSelectedDepts] = useState([]);
  const [selectedStaff, setSelectedStaff] = useState("");
  const [selectedRoom, setSelectedRoom] = useState("");

  const [seating, setSeating] = useState([]);
  const [overflow, setOverflow] = useState([]);

  const [openVisual, setOpenVisual] = useState(false);
  const [notify, setNotify] = useState(false);

  /* ================= FETCH DB DATA ================= */
  useEffect(() => {
    axios.get("http://127.0.0.1:5000/api/students")
      .then(res => setStudents(res.data.students || []));

    axios.get("http://127.0.0.1:5000/api/students/departments")
      .then(res => setDepartments(res.data.departments || []));

    axios.get("http://127.0.0.1:5000/api/staff")
      .then(res => setStaffList(res.data.staff || []));

    axios.get("http://127.0.0.1:5000/api/rooms")
      .then(res => setRooms(res.data.rooms || []));
  }, []);

  /* ================= GENERATE SEATING ================= */
  const generateSeating = () => {
    if (!selectedRoom || !selectedStaff || selectedDepts.length === 0) {
      alert("Select Department, Staff & Room");
      return;
    }

    const room = rooms.find(r => r.room_no === selectedRoom);

    const filteredStudents = students.filter(s =>
      selectedDepts.includes(s.department_name)
    );

    const { seated, overflow } = allocateStudents(filteredStudents, room);

    setSeating(seated);
    setOverflow(overflow);

    if (overflow.length > 0) setNotify(true);
  };

  /* ================= EXPORT PDF ================= */
  const exportPDF = () => {
    const doc = new jsPDF();

    doc.text("Exam Seating Arrangement", 14, 15);
    doc.setFontSize(10);

    doc.text(`Room : ${selectedRoom}`, 14, 25);
    doc.text(`Invigilator : ${selectedStaff}`, 14, 31);
    doc.text(`Departments : ${selectedDepts.join(", ")}`, 14, 37);
    doc.text(`Seated : ${seating.length}`, 14, 43);
    doc.text(`Not Seated : ${overflow.length}`, 14, 49);

    autoTable(doc, {
      startY: 55,
      head: [["Reg No", "Name", "Department"]],
      body: seating.map(s => [
        s.register_no,
        s.student_name,
        s.department_name
      ])
    });

    doc.save("seating-arrangement.pdf");
  };

  return (
    <>
      <Header />
      <Box sx={{ display: "flex" }}>
        <AdminSidebar />

        <Box sx={{ p: 3, flexGrow: 1 }}>
          <Typography variant="h6" mb={2}>
            Seating Arrangement
          </Typography>

          {/* ================= DROPDOWNS ================= */}
          <Box sx={{ display: "flex", gap: 2, mb: 3, flexWrap: "wrap" }}>

            <FormControl size="small" sx={{ minWidth: 220 }}>
              <InputLabel>Department</InputLabel>
              <Select
                multiple
                value={selectedDepts}
                onChange={(e) => setSelectedDepts(e.target.value)}
              >
                {departments.map(d => (
                  <MenuItem key={d} value={d}>{d}</MenuItem>
                ))}
              </Select>
            </FormControl>

            <FormControl size="small" sx={{ minWidth: 200 }}>
              <InputLabel>Invigilator</InputLabel>
              <Select
                value={selectedStaff}
                onChange={(e) => setSelectedStaff(e.target.value)}
              >
                {staffList.map(s => (
                  <MenuItem key={s.id} value={s.staff_name}>
                    {s.staff_name}
                  </MenuItem>
                ))}
              </Select>
            </FormControl>

            <FormControl size="small" sx={{ minWidth: 160 }}>
              <InputLabel>Hall</InputLabel>
              <Select
                value={selectedRoom}
                onChange={(e) => setSelectedRoom(e.target.value)}
              >
                {rooms.map(r => (
                  <MenuItem key={r.id} value={r.room_no}>
                    {r.room_no} ({r.capacity})
                  </MenuItem>
                ))}
              </Select>
            </FormControl>

            <Button variant="contained" onClick={generateSeating}>
              Generate
            </Button>

            {seating.length > 0 && (
              <>
                <Button variant="outlined" onClick={() => setOpenVisual(true)}>
                  VISUALS 👁
                </Button>

                <Button variant="outlined" color="success" onClick={exportPDF}>
                  Export PDF
                </Button>
              </>
            )}
          </Box>

          {/* ================= COUNT ================= */}
          <Typography mb={1} fontWeight={600}>
            Seated : {seating.length} | Remaining : {overflow.length}
          </Typography>

          {/* ================= TABLE ================= */}
          {seating.length > 0 && (
            <Paper>
              <Table>
                <TableHead>
                  <TableRow>
                    <TableCell>S.No</TableCell>
                    <TableCell>Register No</TableCell>
                    <TableCell>Name</TableCell>
                    <TableCell>Department</TableCell>
                  </TableRow>
                </TableHead>
                <TableBody>
                  {seating.map((s, i) => (
                    <TableRow key={s.id}>
                      <TableCell>{i + 1}</TableCell>
                      <TableCell>{s.register_no}</TableCell>
                      <TableCell>{s.student_name}</TableCell>
                      <TableCell>{s.department_name}</TableCell>
                    </TableRow>
                  ))}
                </TableBody>
              </Table>
            </Paper>
          )}
        </Box>
      </Box>

      {/* ================= VISUAL DIALOG ================= */}
      <Dialog open={openVisual} onClose={() => setOpenVisual(false)} maxWidth="md">
        <DialogTitle>
          Hall {selectedRoom} – Seating Visual (Capacity: {rooms.find(r => r.room_no === selectedRoom)?.capacity || 0})
        </DialogTitle>
        <DialogContent>
          <Box sx={{ display: "grid", gridTemplateColumns: "repeat(10, 1fr)", gap: 1 }}>
            {[...Array(
              rooms.find(r => r.room_no === selectedRoom)?.capacity || 0
            )].map((_, i) => (
              <Box
                key={i}
                sx={{
                  border: "1px solid #333",
                  height: 35,
                  display: "flex",
                  alignItems: "center",
                  justifyContent: "center",
                  bgcolor: seating[i] ? "#c8e6c9" : "#ffcdd2",
                  fontWeight: "bold",
                  fontSize: "14px"
                }}
              >
                {seating[i] ? "×" : i + 1}
              </Box>
            ))}
          </Box>
          <Box sx={{ mt: 2, display: "flex", gap: 3 }}>
            <Box sx={{ display: "flex", alignItems: "center", gap: 1 }}>
              <Box sx={{ width: 20, height: 20, bgcolor: "#c8e6c9", border: "1px solid #333", display: "flex", alignItems: "center", justifyContent: "center" }}>×</Box>
              <Typography variant="body2">Occupied ({seating.length})</Typography>
            </Box>
            <Box sx={{ display: "flex", alignItems: "center", gap: 1 }}>
              <Box sx={{ width: 20, height: 20, bgcolor: "#ffcdd2", border: "1px solid #333", display: "flex", alignItems: "center", justifyContent: "center" }}>1</Box>
              <Typography variant="body2">Available ({(rooms.find(r => r.room_no === selectedRoom)?.capacity || 0) - seating.length})</Typography>
            </Box>
          </Box>
        </DialogContent>
      </Dialog>

      {/* ================= WARNING ================= */}
      <Snackbar open={notify} autoHideDuration={5000} onClose={() => setNotify(false)}>
        <Alert severity="warning">
          ⚠ {overflow.length} students not allocated – choose another hall
        </Alert>
      </Snackbar>
    </>
  );
}
